<?php// A file with the database host, user, password, and selected databaseinclude_once('dbconnect.php');// A string used for md5 encryption.  You could move it to a file// outside the web tree for more security.$supersecret_hash_padding = 'A stringetje that is used to pad out short strings for md5 encryption.';function user_register() {  // This function will only work with superglobal arrays, because  // I'm not passing in any values or declaring globals  global $supersecret_hash_padding;  // Are all vars present and passwords match?  if (strlen($_POST['user_name']) <= 25 && strlen($_POST['password1']) <= 25 && ($_POST['password1'] == $_POST['password2']) && strlen($_POST['emailadres']) <= 50 && validate_email($_POST['emailadres'])) {    // Validate username and password    if (account_namevalid($_POST['user_name']) || strlen($_POST['password1'] >= 6)) {      $user_name = strtolower($_POST['user_name']);      $user_name = trim($user_name);      // Don't need to escape, because single quotes aren't allowed      $emailadres= $_POST['emailadres'];      // Don't allow duplicate usernames or emails      $query = "SELECT net_id                FROM steunnetwerk                WHERE net_user_name = '$user_name'                OR net_emailadres = '$emailadres'";      $result = mysql_query($query);      if ($result && mysql_num_rows($result) > 0) {        $feedback = 'ERROR - De <b>account naam</b> of het <b>emailadres</b> bestaat al voor deze locatie';        return $feedback;      } else { 		$voornaam = $_POST['voornaam'];		$achternaam = $_POST['achternaam'];        $password = md5($_POST['password1']);		$user_ip = $_SERVER['REMOTE_ADDR'];        // Create a new hash to insert into the db and the confirmation emailadres        $hash = md5($emailadres.$supersecret_hash_padding);        $query = "INSERT INTO steunnetwerk (net_id, persoon_id, net_user_name, net_emailadres, net_voornaam, net_achternaam, net_paswoord, net_remote_addr, net_confirm_hash, net_is_confirmed, net_date_created, net_gebdat, net_gender, relatietoon, relatietot, relatiegeeft, relatiekost, opdehoogte)                  VALUES (NULL, $persoon_id, '$user_name', '$emailadres', '$voornaam', '$achternaam', '$password', '$user_ip', '$hash', 0, NOW(),'$gebdat', '$gender', '0', '0', '', '', '0')";        $result = mysql_query($query);        if (!$result) {          $feedback = 'Er is een database error ontstaan'; ///@@@@weghalen -->>///           $feedback .= $result;  ///@@@@@weghalen <<--///        return $feedback;        } else {          // Send the confirmation email          $encoded_email = urlencode($_POST['emailadres']);          $mail_body = <<< EOMAILBODYBedankt dat jij jezelf  bij HelpDisk.n/alcohol heeft ingeschreven.  klik op de volgende link:http://www.helpdisk.nl/alcohol/contact/confirm.php?hash=$hash&emailadres=$encoded_emailAls de database uw gegevens valideert kun je aan de slag op www.HelpDisk.nl/Alchol.Mocht iemand anders uw email adres gebruikt hebben om in te loggen dan kun je deze email als niet verzonden beschouwen.EOMAILBODY;          mail ($emailadres, 'www.HelpDisk.nl Registratie geslaagd', $mail_body, 'From: info@helpdisk.nl');	  // Give a successful registration message          $feedback = '<font color="#800040"> <b>Je bent succesvol geregistreerd en ontvangt snel een email met de gegevens waarmee je in kunt loggen.</b></font><P>Klik hier om naar de inlog pagina te gaan:<a href="login.php" target="_self" class="menubutton"> inloggen <img src="../pics/macmanup.gif" width="23" height="28" border="0" align="top"></a>';          return $feedback;        }      }    } else {      $feedback =  'Foutje in accountnaam of paswoord';if (strlen($_POST['password1'] <= 6)){ 	  $feedback .= "<br>Het paswoord dient minimaal 6 karakters lang te zijn";	}if (strlen($_POST['user_name'] <= 6)){ 	  $feedback .= "<br>De Accountnaam dient minimaal 6 karakters lang te zijn";	}  if (!validate_email($_POST['emailadres'])){ 	  $feedback .= "<br>".$_POST['emailadres']."lijkt geen reeel emailadres te zijn...";	}	  	  	     return $feedback;    }  } else {    $feedback = 'Er is een fout ontstaan: wil je <b>alle</b> velden aandachtig invullen, alsjeblieft?'; if ($_POST['password1'] != $_POST['password2']){ 	  $feedback .= "<br>Het eerste en het tweede opgegeven paswoord zijn niet gelijk";	} if (strlen($_POST['user_name']) >= 25){ 	  $feedback .= "<br>Dit lijkt wel een heeeeeel erg lang email adres te zijn... :-(";	}    return $feedback;  }}function account_namevalid() {  // must have at least one character  if (strspn($_POST['user_name'],"abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789-") == 0) {    return false;  }   // must contain all legal characters  if (strspn($_POST['user_name'],"abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789-_") != strlen($_POST['user_name'])) {    return false;  }  // min and max length  if (strlen($_POST['user_name']) < 5) {    return false;  }  if (strlen($_POST['user_name']) > 25) {    return false;  }  // illegal names  if (eregi("^((root)|(bin)|(daemon)|(adm)|(lp)|(sync)|(shutdown)|(halt)|(mail)|(news)|(uucp)|(operator)|(games)|(mysql)|(httpd)|(nobody)|(dummy)|(www)|(cvs)|(shell)|(ftp)|(irc)|(debian)|(ns)|(download))$", $_POST['user_name'])) {    return false;  }  if (eregi("^(anoncvs_)", $_POST['user_name'])) {    return false;  }return true;}function validate_email($emailadres) {  return (ereg('^[-!#$%&\'*+\\./0-9=?A-Z^_`a-z{|}~]+'. '@'. '[-!#$%&\'*+\\/0-9=?A-Z^_`a-z{|}~]+\.' . '[-!#$%&\'*+\\./0-9=?A-Z^_`a-z{|}~]+$', $emailadres));}function user_confirm() {  // This function will only work with superglobal arrays, because  // I'm not passing in any values or declaring globals  global $supersecret_hash_padding;  // Verify that they didn't tamper with the email address  $new_hash = md5($_GET['emailadres'].$supersecret_hash_padding);  if ($new_hash && ($new_hash == $_GET['hash'])) {    $query = "SELECT net_user_name              FROM steunnetwerk              WHERE net_confirm_hash = '$new_hash'";    $result = mysql_query($query);    if (!$result || mysql_num_rows($result) < 1) {      $feedback = 'ERROR - uw code is niet (meer) in de database gevonden';      return $feedback;    } else {      // Confirm the email and set account to active      $emailadres = $_GET['emailadres'];      $hash = $_GET['hash'];      $query = "UPDATE steunnetwerk SET net_emailadres='$emailadres', net_is_confirmed=1 WHERE net_confirm_hash='$hash'";      $result = mysql_query($query);      return 1;    }  } else {    $feedback = 'ERROR - Deze waarden lijken niet te kloppen';    return $feedback;  }}?>